        assertTrue(Permission.checkPermission(Permission.PUB, bothPerms));
        assertTrue(Permission.checkPermission(Permission.SUB, bothPerms));

        // 4. The method returns `true` when the needed permission is any and the owned permissions include both publish and subscribe.
        assertTrue(Permission.checkPermission(Permission.ANY, bothPerms));

