        assertFalse(Permission.checkPermission(Permission.DENY, Permission.ANY));
        assertFalse(Permission.checkPermission(Permission.DENY, Permission.PUB));
        assertFalse(Permission.checkPermission(Permission.DENY, Permission.SUB));
