    @Test
    public void testToString() throws Exception {
        String testString = "testToString";
        String defaultCharset = RemotingHelper.DEFAULT_CHARSET;

        // Test converting an input stream without specifying a charset
        InputStream inputStream1 = new ByteArrayInputStream(testString.getBytes(defaultCharset));
        String result1 = IOTinyUtils.toString(inputStream1, null);
        assertEquals(testString, result1);

        // Test converting an input stream with a specified charset
        InputStream inputStream2 = new ByteArrayInputStream(testString.getBytes(defaultCharset));
        String result2 = IOTinyUtils.toString(inputStream2, defaultCharset);
        assertEquals(testString, result2);

        // Test converting a reader with a specified charset
        Reader reader = new InputStreamReader(new ByteArrayInputStream(testString.getBytes(defaultCharset)), defaultCharset);
        String result3 = IOTinyUtils.toString(reader);
        assertEquals(testString, result3);
    }

}

