public class NamespaceUtilTest {

    private static final String INSTANCE_ID = "MQ_INST_XXX";
    private static final String INSTANCE_ID_WRONG = "MQ_INST_XXX1";
    private static final String TOPIC = "TOPIC_XXX";
    private static final String GROUP_ID = "GID_XXX";
    private static final String SYSTEM_TOPIC = "rmq_sys_topic";
    private static final String GROUP_ID_WITH_NAMESPACE = INSTANCE_ID + NamespaceUtil.NAMESPACE_SEPARATOR + GROUP_ID;
    private static final String TOPIC_WITH_NAMESPACE = INSTANCE_ID + NamespaceUtil.NAMESPACE_SEPARATOR + TOPIC;
    private static final String RETRY_TOPIC = MixAll.RETRY_GROUP_TOPIC_PREFIX + GROUP_ID;
    private static final String RETRY_TOPIC_WITH_NAMESPACE =
        MixAll.RETRY_GROUP_TOPIC_PREFIX + INSTANCE_ID + NamespaceUtil.NAMESPACE_SEPARATOR + GROUP_ID;
    private static final String DLQ_TOPIC = MixAll.DLQ_GROUP_TOPIC_PREFIX + GROUP_ID;
    private static final String DLQ_TOPIC_WITH_NAMESPACE =
        MixAll.DLQ_GROUP_TOPIC_PREFIX + INSTANCE_ID + NamespaceUtil.NAMESPACE_SEPARATOR + GROUP_ID;

    @Test
    public void testWithoutNamespace() {
        // Test normal namespace removal from topic and group ID
        String resultTopic = NamespaceUtil.withoutNamespace(TOPIC_WITH_NAMESPACE, INSTANCE_ID);
        Assert.assertEquals(TOPIC, resultTopic);
        String resultGroup = NamespaceUtil.withoutNamespace(GROUP_ID_WITH_NAMESPACE, INSTANCE_ID);
        Assert.assertEquals(GROUP_ID, resultGroup);

        // Test retry and dead-letter queue topics are correctly processed
        String resultRetry = NamespaceUtil.withoutNamespace(RETRY_TOPIC_WITH_NAMESPACE, INSTANCE_ID);
        Assert.assertEquals(RETRY_TOPIC, resultRetry);
        String resultDLQ = NamespaceUtil.withoutNamespace(DLQ_TOPIC_WITH_NAMESPACE, INSTANCE_ID);
        Assert.assertEquals(DLQ_TOPIC, resultDLQ);

        // Test returns original string when namespace does not match
        String noMatchResult = NamespaceUtil.withoutNamespace(TOPIC_WITH_NAMESPACE, INSTANCE_ID_WRONG);
        Assert.assertEquals(TOPIC_WITH_NAMESPACE, noMatchResult);

        // Test with null or empty inputs
        Assert.assertNull(NamespaceUtil.withoutNamespace(null, INSTANCE_ID));
        Assert.assertEquals("", NamespaceUtil.withoutNamespace("", INSTANCE_ID));
        Assert.assertEquals(TOPIC_WITH_NAMESPACE, NamespaceUtil.withoutNamespace(TOPIC_WITH_NAMESPACE, ""));

        // Test system topic remains unchanged (based on Fact 2 and Referable Test Case)
        String systemResult = NamespaceUtil.withoutNamespace(SYSTEM_TOPIC, INSTANCE_ID);
        Assert.assertEquals(SYSTEM_TOPIC, systemResult);
    }

}

