    private static final String DLQ_TOPIC_WITH_NAMESPACE = MixAll.DLQ_GROUP_TOPIC_PREFIX + INSTANCE_ID + NamespaceUtil.NAMESPACE_SEPARATOR + GROUP_ID;

    @Test
    public void testWrapNamespace() {
        // 1. Normal topics get the namespace added correctly.
        String wrappedNormalTopic = NamespaceUtil.wrapNamespace(INSTANCE_ID, TOPIC);
        Assert.assertEquals(TOPIC_WITH_NAMESPACE, wrappedNormalTopic);

        // 2. Topics already with the namespace stay the same.
        String alreadyWrapped = NamespaceUtil.wrapNamespace(INSTANCE_ID, TOPIC_WITH_NAMESPACE);
        Assert.assertEquals(TOPIC_WITH_NAMESPACE, alreadyWrapped);

