        String wrappedDLQTopic = NamespaceUtil.wrapNamespace(INSTANCE_ID, DLQ_TOPIC);
        Assert.assertEquals(DLQ_TOPIC_WITH_NAMESPACE, wrappedDLQTopic);

        // 5. System topics remain unchanged without any namespace wrapping.
        String wrappedSystemTopic = NamespaceUtil.wrapNamespace(INSTANCE_ID, SYSTEM_TOPIC);
        Assert.assertEquals(SYSTEM_TOPIC, wrappedSystemTopic);

        // Additional edge case: empty namespace or resource returns resource unchanged.
        String emptyNamespaceResult = NamespaceUtil.wrapNamespace("", TOPIC);
        Assert.assertEquals(TOPIC, emptyNamespaceResult);
        String emptyResourceResult = NamespaceUtil.wrapNamespace(INSTANCE_ID, "");
        Assert.assertEquals("", emptyResourceResult);
    }

}

